loopCodePart.item:
// ============================================================
// METEO_CORE_PRO - ADVANCED WEATHER FORECAST ENGINE V4.0
// ============================================================

if (MCP_EN) {
    static unsigned long mcp_last_tick = 0;
    static unsigned long mcp_last_req = 0;
    static unsigned long mcp_cycle_timer = 0;
    static int mcp_current_disp_hour = 1;

    // Output probabilities array 1..6 hours
    static int mcp_p_final[7] = {0, 0, 0, 0, 0, 0, 0};

    // Status flag for Open-Meteo online fetch
    static bool mcp_om_success = false;

    // Compact 200-record ring buffer memory
    struct MCP_Record {
        int8_t temp_x2;      // Temp in C * 2 (-50..+80)
        uint8_t hum;         // Humidity 0..100%
        uint16_t press_hpa;  // Pressure 800..1100 hPa
        int8_t dew_point_x2; // Dew point * 2
        uint8_t day_of_year; // Scaled day of year (1..365 -> 0..255)
        uint8_t rain_flag;   // 1 if rain detected, 0 if dry
        uint8_t prob_out;    // Calculated prob
    };

    static MCP_Record mcp_db[200];
    static uint16_t mcp_db_head = 0;
    static uint16_t mcp_db_count = 0;

    // ------------------------------------------------------------
    // MODULE 1: DEW POINT & LOCAL SENSOR VALIDATION
    // ------------------------------------------------------------
    bool temp_valid = (MCP_TEMP_C >= -50.0f && MCP_TEMP_C <= 80.0f);
    bool hum_valid = (MCP_HUM_PCT >= 0.0f && MCP_HUM_PCT <= 100.0f);
    bool press_valid = false;
    float norm_press = MCP_PRESS_HPA;

    if (norm_press > 80000.0f && norm_press < 110000.0f) {
        norm_press /= 100.0f;
    }
    if (norm_press >= 800.0f && norm_press <= 1100.0f) {
        press_valid = true;
    }

    float local_dew_point = MCP_TEMP_C - ((100.0f - MCP_HUM_PCT) / 5.0f);
    float dew_diff = MCP_TEMP_C - local_dew_point;

    // ------------------------------------------------------------
    // MODULE 2: TREND ANALYZER (10-min & history deltas)
    // ------------------------------------------------------------
    static float prev_press = 1013.25f;
    static float prev_hum = 50.0f;
    static float prev_temp = 20.0f;

    float press_delta = norm_press - prev_press;
    float hum_delta = MCP_HUM_PCT - prev_hum;
    float temp_delta = MCP_TEMP_C - prev_temp;

    // ------------------------------------------------------------
    // MODULE 3: SEASONAL LEARNING & DAY OF YEAR WEIGHT TRANSITION
    // ------------------------------------------------------------
    // Default day estimation fallback if no RTC
    static uint16_t day_of_year = 180; // Summer default mid-year

    // Calculate smooth seasonal bias
    float seasonal_bias = 0.0f;
    if (day_of_year >= 60 && day_of_year < 152) {
        // Spring -> Summer transition
        seasonal_bias = (press_delta < -0.8f) ? 10.0f : 0.0f;
    } else if (day_of_year >= 152 && day_of_year < 244) {
        // Summer peak
        if (MCP_TEMP_C > 25.0f && MCP_HUM_PCT > 70.0f) seasonal_bias = 15.0f;
    } else if (day_of_year >= 244 && day_of_year < 335) {
        // Autumn
        if (MCP_HUM_PCT > 80.0f && press_delta < -0.5f) seasonal_bias = 20.0f;
    } else {
        // Winter
        if (MCP_TEMP_C <= 2.0f && MCP_HUM_PCT > 85.0f) seasonal_bias = 12.0f;
    }

    // ------------------------------------------------------------
    // MODULE 7: ONLINE ENGINE (Open-Meteo HTTP fetch)
    // ------------------------------------------------------------
    int req_min = MCP_REQ_MIN;
    if (req_min < 10) req_min = 10;
    if (req_min > 360) req_min = 360;

    unsigned long req_interval_ms = (unsigned long)req_min * 60000UL;

    if (millis() - mcp_last_req >= req_interval_ms || mcp_last_req == 0) {
        mcp_last_req = millis();
        mcp_om_success = false;

        if (WiFi.status() == WL_CONNECTED) {
            WiFiClient client;
            if (client.connect("api.open-meteo.com", 80)) {
                String url = "/v1/forecast?latitude=" + String(MCP_LAT, 4) +
                             "&longitude=" + String(MCP_LON, 4) +
                             "&hourly=precipitation_probability,precipitation,rain,showers,snowfall,weather_code" +
                             "&forecast_hours=12&timezone=auto";

                client.print(String("GET ") + url + " HTTP/1.1\r\n" +
                             "Host: api.open-meteo.com\r\n" +
                             "Connection: close\r\n\r\n");

                unsigned long timeout = millis();
                while (client.available() == 0) {
                    if (millis() - timeout > 2500) {
                        client.stop();
                        break;
                    }
                }

                if (client.available()) {
                    String response = client.readString();
                    client.stop();

                    int idx = response.indexOf("\"precipitation_probability\":[");
                    if (idx != -1) {
                        int start = idx + 29;
                        int end = response.indexOf("]", start);
                        if (end != -1) {
                            String arrStr = response.substring(start, end);
                            int h = 1;
                            int curPos = 0;
                            while (h <= 6 && curPos < (int)arrStr.length()) {
                                int nextComma = arrStr.indexOf(',', curPos);
                                if (nextComma == -1) nextComma = arrStr.length();
                                String valStr = arrStr.substring(curPos, nextComma);
                                valStr.trim();
                                mcp_p_final[h] = valStr.toInt();
                                curPos = nextComma + 1;
                                h++;
                            }
                            mcp_om_success = true;
                        }
                    }
                }
            }
        }
    }

    // ------------------------------------------------------------
    // MODULE 8: LOCAL ENGINE (Offline model fallback)
    // ------------------------------------------------------------
    float local_base_prob = 0.0f;
    if (temp_valid && hum_valid && press_valid) {
        // Base probability calculated from local physics
        if (MCP_HUM_PCT >= 90.0f) local_base_prob += 40.0f;
        else if (MCP_HUM_PCT >= 80.0f) local_base_prob += 25.0f;
        else if (MCP_HUM_PCT >= 70.0f) local_base_prob += 10.0f;
        else if (MCP_HUM_PCT < 50.0f) local_base_prob -= 15.0f;

        if (press_delta <= -1.5f) local_base_prob += 35.0f;
        else if (press_delta <= -0.8f) local_base_prob += 20.0f;
        else if (press_delta <= -0.4f) local_base_prob += 10.0f;
        else if (press_delta >= 0.8f) local_base_prob -= 20.0f;

        if (dew_diff <= 1.0f) local_base_prob += 20.0f;
        else if (dew_diff <= 2.0f) local_base_prob += 10.0f;

        local_base_prob += seasonal_bias;
    }

    // Combine Online + Local depending on mcp_om_success
    for (int h = 1; h <= 6; h++) {
        if (!mcp_om_success) {
            // Full Offline mode
            float hour_decay = 1.0f - ((h - 1) * 0.08f);
            float calc_p = local_base_prob * hour_decay;
            if (calc_p < 0.0f) calc_p = 0.0f;
            if (calc_p > 100.0f) calc_p = 100.0f;
            mcp_p_final[h] = (int)calc_p;
        } else {
            // Hybrid mode: 60% Online + 40% Local correction
            float combined = (mcp_p_final[h] * 0.60f) + (local_base_prob * 0.40f);
            if (combined < 0.0f) combined = 0.0f;
            if (combined > 100.0f) combined = 100.0f;
            mcp_p_final[h] = (int)combined;
        }
    }

    // ------------------------------------------------------------
    // MODULE 6: RAIN LEARNING & SENSOR VERIFICATION
    // ------------------------------------------------------------
    if (MCP_RAIN_USE && MCP_RAIN_STATE) {
        if (mcp_p_final[1] < 90) mcp_p_final[1] = 90;
        if (mcp_p_final[2] < 70) mcp_p_final[2] = 70;
    }

    // ------------------------------------------------------------
    // MODULE 4 & 5: MEMORY MANAGER (Ring buffer write)
    // ------------------------------------------------------------
    if (millis() - mcp_last_tick >= 600000UL || mcp_last_tick == 0) { // Every 10 mins
        mcp_last_tick = millis();

        prev_press = norm_press;
        prev_hum = MCP_HUM_PCT;
        prev_temp = MCP_TEMP_C;

        if (temp_valid && hum_valid && press_valid) {
            mcp_db[mcp_db_head].temp_x2 = (int8_t)(MCP_TEMP_C * 2.0f);
            mcp_db[mcp_db_head].hum = (uint8_t)MCP_HUM_PCT;
            mcp_db[mcp_db_head].press_hpa = (uint16_t)norm_press;
            mcp_db[mcp_db_head].dew_point_x2 = (int8_t)(local_dew_point * 2.0f);
            mcp_db[mcp_db_head].day_of_year = (uint8_t)((day_of_year * 255) / 365);
            mcp_db[mcp_db_head].rain_flag = (MCP_RAIN_USE && MCP_RAIN_STATE) ? 1 : 0;
            mcp_db[mcp_db_head].prob_out = (uint8_t)mcp_p_final[1];

            mcp_db_head = (mcp_db_head + 1) % 200;
            if (mcp_db_count < 200) mcp_db_count++;
        }
    }

    // ------------------------------------------------------------
    // MODULE 9: FINAL DECISION & DISPLAY OUTPUTS
    // ------------------------------------------------------------
    if (millis() - mcp_cycle_timer >= 20000UL) { // Rotate screen hour every 20s
        mcp_cycle_timer = millis();
        mcp_current_disp_hour++;
        if (mcp_current_disp_hour > 6) mcp_current_disp_hour = 1;
    }

    MCP_OUT_HOUR = mcp_current_disp_hour;
    MCP_OUT_PROB = mcp_p_final[mcp_current_disp_hour];
    MCP_OM_STATUS = mcp_om_success;

    MCP_HOUR_1 = 1; MCP_PROB_1 = mcp_p_final[1];
    MCP_HOUR_2 = 2; MCP_PROB_2 = mcp_p_final[2];
    MCP_HOUR_3 = 3; MCP_PROB_3 = mcp_p_final[3];
    MCP_HOUR_4 = 4; MCP_PROB_4 = mcp_p_final[4];
    MCP_HOUR_5 = 5; MCP_PROB_5 = mcp_p_final[5];
    MCP_HOUR_6 = 6; MCP_PROB_6 = mcp_p_final[6];

} else {
    // Block disabled
    MCP_OUT_HOUR = 1;
    MCP_OUT_PROB = 0;
    MCP_OM_STATUS = false;

    MCP_HOUR_1 = 1; MCP_PROB_1 = 0;
    MCP_HOUR_2 = 2; MCP_PROB_2 = 0;
    MCP_HOUR_3 = 3; MCP_PROB_3 = 0;
    MCP_HOUR_4 = 4; MCP_PROB_4 = 0;
    MCP_HOUR_5 = 5; MCP_PROB_5 = 0;
    MCP_HOUR_6 = 6; MCP_PROB_6 = 0;
}
